1	import express from "express";
2	import session from "express-session";
3	import cors from "cors";
4	import { runMigrations } from "./db.js";
5	import { registerIdentityRoutes } from "./modules/identity/routes.js";
6	import { registerCommunicationRoutes } from "./modules/communication/routes.js";
7	import { registerRaceMgmtRoutes } from "./modules/race-mgmt/routes.js";
8	import { registerPortfolioRoutes } from "./modules/portfolio/routes.js";
9	
10	const app = express();
11	const PORT = process.env.PORT || 3000;
12	
13	// ── Middleware ──
14	app.use(cors({ origin: "http://localhost:5173", credentials: true }));
15	app.use(express.json({ limit: "256kb" }));
16	app.use(
17	  session({
18	    secret: process.env.SESSION_SECRET || "ary-dev-secret-change-in-production",
19	    resave: false,
20	    saveUninitialized: false,
21	    cookie: { secure: false, httpOnly: true, maxAge: 24 * 60 * 60 * 1000 },
22	  }),
23	);
24	
25	// ── Run database migrations ──
26	runMigrations();
27	
28	// ── Module routes ──
29	// To add a new module: import its register function and call it here.
30	// Each module gets its own URL prefix and manages its own routes internally.
31	registerIdentityRoutes(app);       // /auth/*, /admin/*
32	registerCommunicationRoutes(app);  // /communication/*
33	registerRaceMgmtRoutes(app);       // /races/*
34	registerPortfolioRoutes(app);      // /works/*
35	
36	// ── Future modules (uncomment when ready) ──
37	// import { registerProjectionRoutes } from "./modules/projection/routes.js";
38	// registerProjectionRoutes(app);     // /projections/*
39	// import { registerReportGenRoutes } from "./modules/report-gen/routes.js";
40	// registerReportGenRoutes(app);      // /reports/*
41	
42	// ── Health check ──
43	app.get("/health", (_req, res) => {
44	  res.json({ status: "ok", timestamp: new Date().toISOString() });
45	});
46	
47	// ── Global error handler ──
48	app.use((err: any, _req: any, res: any, _next: any) => {
49	  console.error("[ARY] Unhandled error:", err.message || err);
50	  res.status(err.status || 500).json({
51	    error: err.message || "Internal server error",
52	  });
53	});
54	
55	// ── Start ──
56	app.listen(PORT, () => {
57	  console.log(`[ARY] Server running on http://localhost:${PORT}`);
58	});
59	
60	export default app;
61

1	import type { Express, Request, Response } from "express";
