8	const RACE_STATUSES = [
9	  "draft",
10	  "published",
11	  "registration",
12	  "running",
13	  "submitting",
14	  "judging",
15	  "completed",
16	  "archived",
17	] as const;
18	
19	const REGISTRATION_STATUSES = [
20	  "submitted",
21	  "approved",
22	  "rejected",
23	  "withdrawn",
24	] as const;
25	
26	const INGESTION_STATUSES = [
27	  "not_configured",
28	  "connected",
29	  "active",
30	  "failed",
31	] as const;
32	
33	const MAX_SESSION_PAYLOAD_BYTES = 64 * 1024;
34	
35	const CONNECTION_HEALTH = [
36	  "no_signal",
37	  "no_valid_signal",
38	  "healthy",
39	  "partial_failed",
40	] as const;
41	
42	type RaceStatus = typeof RACE_STATUSES[number];
43	type RegistrationStatus = typeof REGISTRATION_STATUSES[number];
44	
45	interface Race {
