47	  slug: string;
48	  title: string;
49	  challenge: string;
50	  status: RaceStatus;
51	  visibility: "private" | "public";
52	  organizer_user_ids: string[];
53	  registration_opens_at: string | null;
54	  registration_closes_at: string | null;
55	  starts_at: string | null;
56	  ends_at: string | null;
57	  created_by_user_id: string;
58	  created_at: string;
59	  updated_at: string;
60	}
61	
62	interface Registration {
63	  id: string;
64	  race_id: string;
65	  user_id: string;
66	  status: RegistrationStatus;
67	  submitted_at: string;
68	  approved_at: string | null;
69	  rejected_at: string | null;
70	  withdrawn_at: string | null;
71	  created_at: string;
72	  updated_at: string;
