88	interface CAConnection {
89	  id: string;
90	  race_project_id: string;
91	  ca_type: string;
92	  ingestion_source: "ca_realtime";
93	  connector_id: string;
94	  connector_version: string | null;
95	  external_project_ref: string | null;
96	  connection_secret: string;
97	  handshake_challenge: string;
98	  handshake_status: "pending" | "verified" | "failed";
99	  handshake_verified_at: string | null;
100	  security_version: "dcr-hmac-v1";
101	  signature_algorithm: "HMAC-SHA256";
102	  last_nonce: string | null;
103	  last_sequence: number;
104	  ingestion_status: typeof INGESTION_STATUSES[number];
105	  registered_at: string;
106	  disabled_at: string | null;
