131	  id: string;
132	  ca_connection_id: string;
133	  race_project_id: string | null;
134	  connector_id: string | null;
135	  accepted: boolean;
136	  reason: string;
137	  detail: string;
138	  nonce: string | null;
139	  sequence: number | null;
140	  payload_hash: string | null;
