244	  router.get("/review", requireLogin, (req: Request, res: Response) => {
245	    const user = getCurrentUser(req);
246	    const races = findAll<Race>("races");
247	
248	    const visible = races.filter((race) => {
249	      if (user?.roles.includes("admin")) return true;
250	      return race.organizer_user_ids.includes(user?.userId || "");
251	    });
252	
253	    res.json({
254	      module: "B",
255	      stage: "B1",
256	      purpose: "Human review for Race CRUD, public visibility, status, organizer scope, and CTA derivation.",
257	      totalRaces: races.length,
258	      reviewableRaces: visible.map((race) => ({
259	        id: race.id,
260	        slug: race.slug,
261	        title: race.title,
262	        status: race.status,
263	        visibility: race.visibility,
264	        organizerUserIds: race.organizer_user_ids,
265	        publicReadable: isPublicRace(race),
266	        cta: deriveRaceCta(race),
267	      })),
268	    });
