271	  router.post("/", requireLogin, (req: Request, res: Response) => {
272	    const user = getCurrentUser(req);
273	    const result = authorize(user, "Race", "create", { allowGlobalOrganizer: true });
274	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
275	
276	    const { title, slug, challenge, registrationOpensAt, registrationClosesAt, startsAt, endsAt } = req.body;
277	    if (!title || typeof title !== "string") {
278	      res.status(400).json({ error: "title is required" });
279	      return;
280	    }
281	
282	    const normalizedSlug = normalizeSlug(slug || title);
283	    if (!normalizedSlug) {
284	      res.status(400).json({ error: "slug or title must produce a valid slug" });
285	      return;
286	    }
287	
288	    const existing = findBy<Race>("races", "slug", normalizedSlug);
289	    if (existing) {
290	      res.status(409).json({ error: "slug already exists" });
291	      return;
292	    }
293	
294	    const now = new Date().toISOString();
295	    const race: Race = {
296	      id: uuid(),
297	      slug: normalizedSlug,
298	      title: title.trim(),
299	      challenge: typeof challenge === "string" ? challenge.trim() : "",
300	      status: "draft",
301	      visibility: "private",
302	      organizer_user_ids: [user!.userId],
303	      registration_opens_at: optionalString(registrationOpensAt),
304	      registration_closes_at: optionalString(registrationClosesAt),
305	      starts_at: optionalString(startsAt),
306	      ends_at: optionalString(endsAt),
307	      created_by_user_id: user!.userId,
308	      created_at: now,
309	      updated_at: now,
310	    };
