326	  router.patch("/:id", requireLogin, (req: Request, res: Response) => {
327	    const race = findById<Race>("races", req.params.id);
328	    if (!race) { res.status(404).json({ error: "Race not found" }); return; }
329	
330	    const auth = authorizeManagedRace(req, race, "edit");
331	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
332	
333	    const updates: Partial<Race> = {};
334	    const { title, challenge, status, registrationOpensAt, registrationClosesAt, startsAt, endsAt } = req.body;
335	
336	    if (title !== undefined) {
337	      if (!title || typeof title !== "string") { res.status(400).json({ error: "title must be a non-empty string" }); return; }
338	      updates.title = title.trim();
339	    }
340	    if (challenge !== undefined) {
341	      if (typeof challenge !== "string") { res.status(400).json({ error: "challenge must be a string" }); return; }
342	      updates.challenge = challenge.trim();
343	    }
344	    if (status !== undefined) {
345	      if (!isRaceStatus(status)) { res.status(400).json({ error: "Invalid race status" }); return; }
346	      if (!canTransitionRaceStatus(race.status, status)) {
347	        res.status(409).json({ error: `Invalid race status transition: ${race.status} -> ${status}` });
348	        return;
349	      }
350	      updates.status = status;
351	    }
352	    if (registrationOpensAt !== undefined) updates.registration_opens_at = optionalString(registrationOpensAt);
353	    if (registrationClosesAt !== undefined) updates.registration_closes_at = optionalString(registrationClosesAt);
354	    if (startsAt !== undefined) updates.starts_at = optionalString(startsAt);
355	    if (endsAt !== undefined) updates.ends_at = optionalString(endsAt);
356	
357	    updates.updated_at = new Date().toISOString();
358	    const updated = update<Race>("races", race.id, updates);
359	    res.json(toRaceResponse(updated!));
