400	  router.post("/:id/registrations", requireLogin, (req: Request, res: Response) => {
401	    const user = getCurrentUser(req);
402	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
403	
404	    const race = findById<Race>("races", req.params.id);
405	    if (!race || !isPublicRace(race)) {
406	      res.status(404).json({ error: "Race not found" });
407	      return;
408	    }
409	
410	    if (race.status !== "registration") {
411	      res.status(409).json({ error: "Race is not open for registration" });
412	      return;
413	    }
414	
415	    const result = authorize(user, "Registration", "submit", { ownerUserId: user.userId });
416	    if (!result.allowed) { res.status(403).json({ error: result.reason }); return; }
417	
418	    const duplicate = findAll<Registration>("registrations")
419	      .find((registration) => registration.race_id === race.id && registration.user_id === user.userId);
420	    if (duplicate) {
421	      res.status(409).json({ error: "User already has a registration for this race", registration: toRegistrationResponse(duplicate, race) });
422	      return;
423	    }
424	
425	    const now = new Date().toISOString();
426	    const registration: Registration = {
427	      id: uuid(),
428	      race_id: race.id,
429	      user_id: user.userId,
430	      status: "submitted",
431	      submitted_at: now,
432	      approved_at: null,
433	      rejected_at: null,
434	      withdrawn_at: null,
435	      created_at: now,
436	      updated_at: now,
437	    };
438	
439	    insert("registrations", registration);
440	    res.status(201).json(toRegistrationResponse(registration, race));
