443	  router.get("/:id/registrations", requireLogin, (req: Request, res: Response) => {
444	    const race = findById<Race>("races", req.params.id);
445	    if (!race) { res.status(404).json({ error: "Race not found" }); return; }
446	
447	    const auth = authorizeManagedRace(req, race, "view_private");
448	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
449	
450	    const registrations = filterRegistrationsByRace(race.id);
451	    res.json(registrations.map((registration) => toRegistrationResponse(registration, race)));
