453	
454	  router.get("/:id/registrations/review", requireLogin, (req: Request, res: Response) => {
455	    const race = findById<Race>("races", req.params.id);
456	    if (!race) { res.status(404).json({ error: "Race not found" }); return; }
457	
458	    const auth = authorizeManagedRace(req, race, "view_private");
459	    if (!auth.allowed) { res.status(403).json({ error: auth.reason }); return; }
460	
461	    const registrations = filterRegistrationsByRace(race.id);
462	    const duplicateKeys = findDuplicateRegistrationKeys(registrations);
463	
464	    res.json({
465	      module: "B",
466	      stage: "B2",
467	      purpose: "Human review for registration list, duplicate protection, approval actions, and non-CA-gated participation status.",
468	      race: {
469	        id: race.id,
470	        slug: race.slug,
471	        title: race.title,
472	        status: race.status,
473	        visibility: race.visibility,
474	      },
475	      summary: {
476	        total: registrations.length,
477	        submitted: registrations.filter((r) => r.status === "submitted").length,
478	        approved: registrations.filter((r) => r.status === "approved").length,
479	        rejected: registrations.filter((r) => r.status === "rejected").length,
480	        withdrawn: registrations.filter((r) => r.status === "withdrawn").length,
481	        duplicateRegistrationKeys: duplicateKeys,
482	      },
483	      registrations: registrations.map((registration) => ({
484	        ...toRegistrationResponse(registration, race),
485	        availableActions: deriveRegistrationActions(registration),
486	        raceProject: registration.status === "approved" ? toRaceProjectResponse(findRaceProjectByRegistrationId(registration.id)) : null,
487	      })),
488	    });
489	  });
490	
491	  registrationsRouter.get("/me", requireLogin, (req: Request, res: Response) => {
492	    const user = getCurrentUser(req);
493	    if (!user) { res.status(401).json({ error: "Not authenticated" }); return; }
494	
495	    const registrations = findAll<Registration>("registrations")
496	      .filter((registration) => registration.user_id === user.userId)
497	      .sort((a, b) => b.created_at.localeCompare(a.created_at));
498	
499	    res.json(registrations.map((registration) => {
500	      const race = findById<Race>("races", registration.race_id);
501	      return {
502	        ...toRegistrationResponse(registration, race || undefined),
503	        raceProject: registration.status === "approved" ? toRaceProjectResponse(findRaceProjectByRegistrationId(registration.id)) : null,
504	      };
505	    }));
506	  });
507	
508	  registrationsRouter.get("/:id/race-project", requireLogin, (req: Request, res: Response) => {
509	    const registration = findById<Registration>("registrations", req.params.id);
510	    if (!registration) { res.status(404).json({ error: "Registration not found" }); return; }
511	
512	    const race = findById<Race>("races", registration.race_id);
513	    if (!canReadRegistrationScopedResource(req, registration, race || undefined)) {
514	      res.status(403).json({ error: "Not allowed to view race project" });
515	      return;
516	    }
517	
518	    const raceProject = findRaceProjectByRegistrationId(registration.id);
519	    if (!raceProject) { res.status(404).json({ error: "RaceProject not found" }); return; }
520	
521	    res.json(toRaceProjectResponse(raceProject));
522	  });
523	
