985	function deriveRaceCta(race: Race) {
986	  if (race.status === "registration") return { label: "Register", target: `/races/${race.slug}` };
987	  if (race.status === "running" || race.status === "submitting") return { label: "Open Live Hall", target: `/races/${race.slug}/live` };
988	  if (race.status === "judging") return { label: "Review in progress", target: `/races/${race.slug}` };
989	  if (race.status === "completed") return { label: "View results", target: `/races/${race.slug}/results` };
990	  if (race.status === "archived") return { label: "Archived", target: `/races/${race.slug}` };
991	  return { label: "View race", target: `/races/${race.slug}` };
992	}
