38	  const [message, setMessage] = useState("");
39	  const [caReviews, setCaReviews] = useState<Record<string, CAReview>>({});
40	  const [ingestionReviews, setIngestionReviews] = useState<Record<string, IngestionReview>>({});
41	
42	  useEffect(() => {
43	    loadRaces();
44	  }, []);
45	
46	  useEffect(() => {
47	    if (!selectedRaceId) {
48	      setReview(null);
49	      return;
50	    }
51	    loadRegistrationReview(selectedRaceId);
52	  }, [selectedRaceId]);
53	
54	  const selectedRace = races.find((race) => race.id === selectedRaceId);
55	  const nextRaceAction = selectedRace ? getNextRaceAction(selectedRace.status) : null;
56	  const caSummary = useMemo(() => summarizeCA(caReviews), [caReviews]);
57	  const riskCount = useMemo(() => {
58	    if (!review) return 0;
59	    return review.registrations.filter((registration) => {
60	      if (!registration.raceProject) return registration.status === "approved";
61	      const ca = caReviews[registration.raceProject.id];
62	      return !ca || ca.summary.total === 0 || ca.summary.pendingHandshake > 0 || ca.summary.failedHandshake > 0 || ca.summary.disabled > 0;
63	    }).length;
64	  }, [caReviews, review]);
65	
66	  const loadRaces = () => {
67	    fetch("/races/review", { credentials: "include" })
68	      .then((res) => (res.ok ? res.json() : null))
69	      .then((data) => {
70	        const items = data?.reviewableRaces || [];
71	        setRaces(items);
72	        setSelectedRaceId((current) => (items.some((race: RaceReviewItem) => race.id === current) ? current : items[0]?.id || ""));
73	      })
74	      .catch(() => setMessage("赛事列表加载失败。"));
75	  };
76	
77	  const loadRegistrationReview = (raceId: string) => {
78	    fetch(`/races/${raceId}/registrations/review`, { credentials: "include" })
79	      .then((res) => (res.ok ? res.json() : null))
80	      .then((data) => {
81	        setReview(data);
82	        (data?.registrations || []).forEach((registration: RegistrationReview["registrations"][number]) => {
83	          if (registration.raceProject) loadCAReview(registration.raceProject.id);
