87	  };
88	
89	  const loadCAReview = (raceProjectId: string) => {
90	    fetch(`/race-projects/${raceProjectId}/ca-review`, { credentials: "include" })
91	      .then((res) => (res.ok ? res.json() : null))
92	      .then((data) => {
93	        if (data) {
94	          setCaReviews((current) => ({ ...current, [raceProjectId]: data }));
95	          data.connections?.forEach((connection: CAReview["connections"][number]) => loadIngestionReview(connection.id));
96	        }
97	      })
98	      .catch(() => {});
99	  };
100	
101	  const loadIngestionReview = (connectionId: string) => {
102	    fetch(`/ca-connections/${connectionId}/ingestion-review`, { credentials: "include" })
103	      .then((res) => (res.ok ? res.json() : null))
104	      .then((data) => {
105	        if (data) setIngestionReviews((current) => ({ ...current, [connectionId]: data }));
106	      })
107	      .catch(() => {});
108	  };
109	
110	  const act = async (registrationId: string, action: "approve" | "reject" | "withdraw") => {
111	    const res = await fetch(`/registrations/${registrationId}/${action}`, {
112	      method: "POST",
