125	        ? await fetch(`/races/${selectedRace.id}/archive`, { method: "POST", credentials: "include" })
126	        : await fetch(`/races/${selectedRace.id}`, {
127	            method: "PATCH",
128	            headers: { "Content-Type": "application/json" },
129	            credentials: "include",
130	            body: JSON.stringify({ status: nextRaceAction.nextStatus }),
131	          });
132	    const data = await res.json().catch(() => null);
133	    setMessage(res.ok ? `${nextRaceAction.label}已完成。` : data?.error || `${nextRaceAction.label}失败。`);
