234	function summarizeCA(rows: Record<string, CAReview>) {
235	  return Object.values(rows).reduce(
236	    (sum, item) => ({
237	      total: sum.total + item.summary.total,
238	      verified: sum.verified + item.summary.verified,
239	      blocked: sum.blocked + item.summary.failedHandshake + item.summary.disabled,
240	    }),
241	    { total: 0, verified: 0, blocked: 0 },
242	  );
243	}
