251	function getNextRaceAction(status: string): { kind: "publish" | "patch" | "archive"; nextStatus?: string; label: string } | null {
252	  if (status === "draft") return { kind: "publish", label: "发布赛事" };
253	  if (status === "published") return { kind: "patch", nextStatus: "registration", label: "开放报名" };
254	  if (status === "registration") return { kind: "patch", nextStatus: "running", label: "开始比赛" };
255	  if (status === "running") return { kind: "patch", nextStatus: "submitting", label: "进入提交阶段" };
256	  if (status === "submitting") return { kind: "patch", nextStatus: "judging", label: "进入评审阶段" };
257	  if (status === "judging") return { kind: "patch", nextStatus: "completed", label: "完成赛事" };
258	  if (status === "completed") return { kind: "archive", label: "归档赛事" };
259	  return null;
260	}
