304	async function signChallenge(secretHex: string, challenge: string) {
305	  const key = await crypto.subtle.importKey(
306	    "raw",
307	    hexToBytes(secretHex),
308	    { name: "HMAC", hash: "SHA-256" },
309	    false,
310	    ["sign"],
311	  );
312	  const signature = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(challenge));
313	  return bytesToHex(new Uint8Array(signature));
314	}
315	
316	function hexToBytes(value: string) {
317	  const bytes = new Uint8Array(value.length / 2);
318	  for (let index = 0; index < bytes.length; index += 1) {
319	    bytes[index] = Number.parseInt(value.slice(index * 2, index * 2 + 2), 16);
320	  }
321	  return bytes;
322	}
323	
324	function bytesToHex(bytes: Uint8Array) {
325	  return Array.from(bytes).map((byte) => byte.toString(16).padStart(2, "0")).join("");
326	}
