1	import { existsSync, mkdirSync, readFileSync, readdirSync, writeFileSync } from "node:fs";
2	import { join, dirname } from "node:path";
3	import { fileURLToPath } from "node:url";
4	
5	const __dirname = dirname(fileURLToPath(import.meta.url));
6	const DATA_DIR = join(__dirname, "..", "..", "database", "data");
7	const MIGRATIONS_DIR = join(__dirname, "..", "..", "database", "migrations");
8	
9	// ── JSON file store ──
10	// Each "table" is a JSON file containing an array of rows.
11	// For MVP this is sufficient; swap to PostgreSQL/SQLite later.
12	
13	function tablePath(name: string): string {
14	  return join(DATA_DIR, `${name}.json`);
15	}
16	
17	export function readTable<T = Record<string, unknown>>(name: string): T[] {
18	  const path = tablePath(name);
19	  if (!existsSync(path)) return [];
20	  try {
21	    return JSON.parse(readFileSync(path, "utf-8")) as T[];
22	  } catch {
23	    return [];
24	  }
25	}
26	
27	function writeTable(name: string, rows: unknown[]): void {
28	  if (!existsSync(DATA_DIR)) mkdirSync(DATA_DIR, { recursive: true });
29	  writeFileSync(tablePath(name), JSON.stringify(rows, null, 2), "utf-8");
30	}
31	
32	export function findAll<T = Record<string, unknown>>(name: string): T[] {
33	  return readTable<T>(name);
34	}
35	
36	export function findById<T = Record<string, unknown>>(name: string, id: string, idField = "id"): T | null {
37	  const rows = readTable<T>(name);
38	  return (rows.find((r: any) => r[idField] === id) as T) ?? null;
39	}
40	
41	export function findBy<T = Record<string, unknown>>(name: string, field: string, value: unknown): T | null {
42	  const rows = readTable<T>(name);
43	  return (rows.find((r: any) => r[field] === value) as T) ?? null;
44	}
45	
46	export function filterBy<T = Record<string, unknown>>(name: string, field: string, value: unknown): T[] {
47	  const rows = readTable<T>(name);
48	  return rows.filter((r: any) => r[field] === value) as T[];
49	}
50	
51	export function insert<T = Record<string, unknown>>(name: string, row: T): T {
52	  const rows = readTable<T>(name);
53	  rows.push(row);
54	  writeTable(name, rows);
55	  return row;
56	}
57	
58	export function update<T = Record<string, unknown>>(name: string, id: string, updates: Partial<T>, idField = "id"): T | null {
59	  const rows = readTable<T>(name);
60	  const idx = rows.findIndex((r: any) => r[idField] === id);
61	  if (idx === -1) return null;
62	  rows[idx] = { ...rows[idx], ...updates } as T;
63	  writeTable(name, rows);
64	  return rows[idx];
65	}
66	
67	export function remove<T = Record<string, unknown>>(name: string, id: string, idField = "id"): boolean {
68	  const rows = readTable<T>(name);
69	  const idx = rows.findIndex((r: any) => r[idField] === id);
70	  if (idx === -1) return false;
71	  rows.splice(idx, 1);
72	  writeTable(name, rows);
73	  return true;
74	}
75	
76	// ── Migrations ──
77	export function runMigrations(): void {
78	  if (!existsSync(MIGRATIONS_DIR)) {
79	    console.log("[db] No migrations directory — skipping");
80	    return;
81	  }
82	
83	  // Track which migrations have been run
84	  const migrated: string[] = readTable<{ name: string }>("_migrations").map(r => r.name);
85	
86	  const entries = readdirSync(MIGRATIONS_DIR)
87	    .filter(f => f.endsWith(".sql"))
88	    .sort();
89	
90	  for (const file of entries) {
91	    if (migrated.includes(file)) continue;
92	    console.log(`[db] Migration: ${file}`);
93	    insert("_migrations", { name: file });
94	  }
95	}
96	
97	// ── CLI ──
98	const arg = process.argv[2];
99	if (arg === "--migrate") {
100	  runMigrations();
101	  console.log("[db] Migrations complete.");
102	  process.exit(0);
103	}
