16	function canonical(value) {
17	  if (value === null || typeof value !== "object") return JSON.stringify(value);
18	  if (Array.isArray(value)) return `[${value.map(canonical).join(",")}]`;
19	  return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${canonical(value[key])}`).join(",")}}`;
20	}
21	
22	function sha256(value) {
23	  return crypto.createHash("sha256").update(value).digest("hex");
24	}
25	
26	function hmac(secret, value) {
27	  return crypto.createHmac("sha256", secret).update(value).digest("hex");
28	}
29	
30	function writeJson(name, value) {
31	  const file = path.join(tmpDir, `${name}-${Date.now()}-${Math.random()}.json`);
32	  fs.writeFileSync(file, JSON.stringify(value), "utf8");
33	  return file;
34	}
