36	function curl(args) {
37	  return new Promise((resolve) => {
38	    const child = spawn("curl.exe", ["--max-time", "5", "-s", ...args]);
39	    let stdout = "";
40	    let stderr = "";
41	    child.stdout.on("data", (chunk) => { stdout += chunk; });
42	    child.stderr.on("data", (chunk) => { stderr += chunk; });
43	    child.on("close", (code) => resolve({ code, stdout, stderr }));
44	  });
45	}
