47	async function postJson(url, value, cookie) {
48	  const args = [];
49	  if (cookie) args.push("-b", cookie);
50	  args.push("-H", "Content-Type: application/json", "--data-binary", `@${writeJson("ary-smoke", value)}`, url);
51	  return parseJson(await curl(args));
52	}
53	
54	async function postJsonWithStatus(url, value, cookie) {
55	  const args = [];
56	  if (cookie) args.push("-b", cookie);
57	  args.push("-H", "Content-Type: application/json", "--data-binary", `@${writeJson("ary-smoke", value)}`, "-w", "\n%{http_code}", url);
58	  return parseJsonWithStatus(await curl(args));
59	}
60	
61	async function patchJsonWithStatus(url, value, cookie) {
62	  const args = ["-X", "PATCH"];
63	  if (cookie) args.push("-b", cookie);
64	  args.push("-H", "Content-Type: application/json", "--data-binary", `@${writeJson("ary-smoke", value)}`, "-w", "\n%{http_code}", url);
65	  return parseJsonWithStatus(await curl(args));
66	}
67	
68	async function postEmptyWithStatus(url, cookie) {
69	  const args = [];
70	  if (cookie) args.push("-b", cookie);
71	  args.push("-X", "POST", "-w", "\n%{http_code}", url);
72	  return parseJsonWithStatus(await curl(args));
73	}
74	
75	async function getJson(url, cookie) {
76	  const args = [];
77	  if (cookie) args.push("-b", cookie);
78	  args.push(url);
79	  return parseJson(await curl(args));
80	}
81	
82	function parseJson(result) {
83	  try {
84	    return JSON.parse(result.stdout || "{}");
85	  } catch {
86	    return { raw: result.stdout, stderr: result.stderr, code: result.code };
87	  }
88	}
89	
90	function parseJsonWithStatus(result) {
91	  const output = result.stdout || "";
92	  const index = output.lastIndexOf("\n");
93	  const body = index >= 0 ? output.slice(0, index) : output;
94	  const status = Number(index >= 0 ? output.slice(index + 1) : 0);
95	  let json;
96	  try {
97	    json = JSON.parse(body || "{}");
98	  } catch {
99	    json = { raw: body };
100	  }
101	  return { status, body: json, stderr: result.stderr, code: result.code };
102	}
