104	function setOrganizerRole(userId) {
105	  const usersPath = path.join(dataDir, "users.json");
106	  const users = JSON.parse(fs.readFileSync(usersPath, "utf8"));
107	  const user = users.find((row) => row.id === userId);
108	  user.roles = ["organizer"];
109	  fs.writeFileSync(usersPath, JSON.stringify(users, null, 2));
110	}
