112	function makeEnvelope(secret, connection, raceProjectId, nonce, sequence, overrides = {}) {
113	  const payload = {
114	    caConnectionId: connection.id,
115	    raceProjectId,
116	    startedAt: new Date().toISOString(),
117	    messageCount: 3,
118	    toolCallCount: 1,
119	    tokenCost: 42,
120	    ...(overrides.payload || {}),
121	  };
122	  const envelope = {
123	    caConnectionId: connection.id,
124	    connectorId: connection.connectorId,
125	    timestamp: new Date().toISOString(),
126	    nonce,
127	    sequence,
128	    payloadHash: sha256(canonical(payload)),
129	    payload,
130	    ...(overrides.envelope || {}),
131	  };
132	  const signed = {
133	    caConnectionId: envelope.caConnectionId,
134	    connectorId: envelope.connectorId,
135	    timestamp: envelope.timestamp,
136	    nonce: envelope.nonce,
137	    sequence: envelope.sequence,
138	    payloadHash: envelope.payloadHash,
139	    payload: envelope.payload,
140	  };
141	  envelope.signature = overrides.signature ?? hmac(secret, canonical(signed));
142	  return envelope;
143	}
