145	async function cleanup() {
146	  for (const name of ["users.json", "races.json", "registrations.json", "race_projects.json", "ca_connections.json", "sessions.json", "ingestion_audits.json"]) {
147	    try { fs.unlinkSync(path.join(dataDir, name)); } catch {}
148	  }
149	  for (const file of [orgCookie, riderCookie]) {
150	    try { fs.unlinkSync(file); } catch {}
151	  }
152	}
