158	async function main() {
159	  await cleanup();
160	  const server = spawn(process.execPath, ["dist/app.js"], {
161	    cwd: path.join(root, "server"),
162	    env: { ...process.env, PORT: port },
163	    stdio: "ignore",
164	  });
165	
166	  try {
167	    await wait(2000);
168	    const org = parseJson(await curl(["-c", orgCookie, "-H", "Content-Type: application/json", "--data-binary", `@${writeJson("org", { githubAccount: "smoke-org", displayName: "Smoke Organizer" })}`, `${base}/auth/github`]));
169	    await curl(["-c", riderCookie, "-H", "Content-Type: application/json", "--data-binary", `@${writeJson("rider", { githubAccount: "smoke-rider", displayName: "Smoke Rider" })}`, `${base}/auth/github`]);
170	    setOrganizerRole(org.userId);
171	
172	    const race = await postJson(`${base}/races`, { title: "Smoke Race", slug: "smoke-race", challenge: "Race management smoke test." }, orgCookie);
173	    const invalidStatus = await patchJsonWithStatus(`${base}/races/${race.id}`, { status: "completed" }, orgCookie);
174	    assert(invalidStatus.status === 409, "Expected invalid race status jump to be rejected");
175	    await curl(["-b", orgCookie, "-X", "POST", `${base}/races/${race.id}/publish`]);
176	    await curl(["-b", orgCookie, "-X", "PATCH", "-H", "Content-Type: application/json", "--data-binary", `@${writeJson("race-status", { status: "registration" })}`, `${base}/races/${race.id}`]);
177	
178	    const registration = parseJson(await curl(["-b", riderCookie, "-X", "POST", `${base}/races/${race.id}/registrations`]));
179	    const duplicateRegistration = await postEmptyWithStatus(`${base}/races/${race.id}/registrations`, riderCookie);
180	    assert(duplicateRegistration.status === 409, "Expected duplicate registration to be rejected");
181	    const approved = parseJson(await curl(["-b", orgCookie, "-X", "POST", `${base}/registrations/${registration.id}/approve`]));
182	    const approvedAgain = parseJson(await curl(["-b", orgCookie, "-X", "POST", `${base}/registrations/${registration.id}/approve`]));
183	    const projectId = approved.raceProject.id;
184	    assert(approvedAgain.raceProject.id === projectId, "Expected repeated approval to reuse the same RaceProject");
185	
186	    const connection = await postJson(`${base}/race-projects/${projectId}/ca-connections`, { caType: "codex", connectorVersion: "dcr-smoke" }, riderCookie);
187	    const unverified = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-unverified", 1);
188	    const unverifiedPush = await postJsonWithStatus(`${base}/ca-connections/${connection.id}/sessions/push`, unverified);
189	    assert(unverifiedPush.status === 403 && unverifiedPush.body.reason === "handshake_not_verified", "Expected unverified connection push to be rejected");
190	    const handshake = {
191	      connectorId: connection.connectorId,
192	      challenge: connection.handshakeChallenge,
193	      securityVersion: "dcr-hmac-v1",
194	      signatureAlgorithm: "HMAC-SHA256",
195	      signature: hmac(connection.connectionSecret, connection.handshakeChallenge),
196	    };
197	    await postJson(`${base}/ca-connections/${connection.id}/handshake`, handshake, riderCookie);
198	
199	    const legal = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-001", 1);
200	    await postJson(`${base}/ca-connections/${connection.id}/sessions/push`, legal);
201	    await postJson(`${base}/ca-connections/${connection.id}/sessions/push`, legal);
202	
203	    const poisonedNonce = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-poison", 2, {
204	      signature: "00",
205	    });
206	    const poisonedNonceRejected = await postJsonWithStatus(`${base}/ca-connections/${connection.id}/sessions/push`, poisonedNonce);
207	    assert(poisonedNonceRejected.status === 403 && poisonedNonceRejected.body.reason === "signature_mismatch", "Expected invalid signature to be rejected without consuming nonce");
208	    const legalAfterPoison = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-poison", 2);
209	    const legalAfterPoisonAccepted = await postJsonWithStatus(`${base}/ca-connections/${connection.id}/sessions/push`, legalAfterPoison);
210	    assert(legalAfterPoisonAccepted.status === 201, "Expected valid push to be accepted after prior invalid signature used same nonce");
211	
212	    const tampered = JSON.parse(JSON.stringify(legal));
213	    tampered.nonce = "smoke-nonce-002";
214	    tampered.sequence = 3;
215	    tampered.payload.tokenCost = 1;
216	    await postJson(`${base}/ca-connections/${connection.id}/sessions/push`, tampered);
217	
218	    const wrongProject = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-003", 4, {
219	      payload: { raceProjectId: "wrong-project-id" },
220	    });
221	    await postJson(`${base}/ca-connections/${connection.id}/sessions/push`, wrongProject);
222	
223	    const oversizedPayload = makeEnvelope(connection.connectionSecret, connection, projectId, "smoke-nonce-large", 5, {
224	      payload: { oversized: "x".repeat(70 * 1024) },
225	    });
226	    const oversizedRejected = await postJsonWithStatus(`${base}/ca-connections/${connection.id}/sessions/push`, oversizedPayload);
227	    assert(oversizedRejected.status === 403 && oversizedRejected.body.reason === "payload_too_large", "Expected oversized payload to be rejected");
228	
229	    const disabledConnection = await postJson(`${base}/race-projects/${projectId}/ca-connections`, { caType: "codex", connectorVersion: "dcr-smoke-disabled" }, riderCookie);
230	    await postJson(`${base}/ca-connections/${disabledConnection.id}/handshake`, {
231	      connectorId: disabledConnection.connectorId,
232	      challenge: disabledConnection.handshakeChallenge,
233	      securityVersion: "dcr-hmac-v1",
234	      signatureAlgorithm: "HMAC-SHA256",
235	      signature: hmac(disabledConnection.connectionSecret, disabledConnection.handshakeChallenge),
236	    }, riderCookie);
237	    await curl(["-b", riderCookie, "-X", "POST", `${base}/ca-connections/${disabledConnection.id}/disable`]);
238	    const disabledPush = await postJsonWithStatus(
239	      `${base}/ca-connections/${disabledConnection.id}/sessions/push`,
240	      makeEnvelope(disabledConnection.connectionSecret, disabledConnection, projectId, "smoke-nonce-disabled", 1),
241	    );
242	    assert(disabledPush.status === 403 && disabledPush.body.reason === "connection_disabled", "Expected disabled connection push to be rejected");
243	
244	    const review = await getJson(`${base}/ca-connections/${connection.id}/ingestion-review`, orgCookie);
245	    const status = await getJson(`${base}/race-projects/${projectId}/status-review`, orgCookie);
246	
247	    assert(review.summary.acceptedSessions === 2, "Expected accepted sessions to include valid push after nonce poisoning attempt");
248	    assert(review.summary.rejectedPushes >= 4, "Expected rejected attack pushes");
249	    assert(review.audits.every((audit) => audit.nonce === undefined && audit.payload_hash === undefined && audit.payloadHash === undefined), "Expected ingestion review to redact nonce and payload hash");
250	    assert(status.raceProject.aggregateIngestionStatus === "active", "Expected RaceProject active status");
251	
252	    console.log(JSON.stringify({
253	      ok: true,
254	      acceptedSessions: review.summary.acceptedSessions,
255	      rejectedPushes: review.summary.rejectedPushes,
256	      aggregateIngestionStatus: status.raceProject.aggregateIngestionStatus,
257	      connectionHealth: status.raceProject.connectionHealth,
258	      duplicateRegistrationRejected: duplicateRegistration.status === 409,
259	      repeatedApprovalIdempotent: approvedAgain.raceProject.id === projectId,
260	      invalidStatusTransitionRejected: invalidStatus.status === 409,
261	      rejectedNonceDoesNotBurn: legalAfterPoisonAccepted.status === 201,
262	    }, null, 2));
263	  } finally {
264	    server.kill();
265	    await wait(300);
266	    await cleanup();
267	  }
268	}
269	
